import { supabase } from "./firebase";
import { uploadImageToImgBB } from "./imgbb";

export interface Message {
  id: string;
  sender: string;
  senderName: string;
  text?: string;
  photoUrl?: string;
  timestamp: number;
  type: "text" | "sticker" | "voice" | "call" | "photo";
  stickerId?: string;
  voiceData?: { duration: number; url: string };
  callDuration?: number;
  reactions?: { [emoji: string]: string[] };
  isEdited?: boolean;
  editedAt?: number;
  isRead?: boolean;
  readAt?: number;
  replyTo?: {
    messageId: string;
    senderName: string;
    text: string;
  };
}

export interface Chat {
  id: string;
  name: string;
  type: "private" | "group" | "channel" | "favorites";
  createdAt: number;
  members: string[];
  messages: Message[];
  avatarUrl?: string;
}

export const createChat = async (
  chatName: string,
  chatType: "private" | "group" | "channel",
  members: string[]
) => {
  try {
    const { data, error } = await supabase
      .from("chats")
      .insert({
        name: chatName,
        is_group: chatType !== "private",
        created_at: new Date().toISOString(),
      })
      .select();

    if (error) throw error;
    return data?.[0]?.id;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const sendMessage = async (
  chatId: string,
  sender: string,
  senderName: string,
  text: string,
  replyTo?: { messageId: string; senderName: string; text: string }
) => {
  try {
    const { error } = await supabase.from("messages").insert({
      chat_id: chatId,
      user_id: sender,
      content: text,
      message_type: "text",
      created_at: new Date().toISOString(),
    });

    if (error) throw error;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const getMessages = async (chatId: string): Promise<Message[]> => {
  try {
    const { data, error } = await supabase
      .from("messages")
      .select("*")
      .eq("chat_id", chatId)
      .order("created_at", { ascending: true });

    if (error) throw error;

    return (
      data?.map((msg) => ({
        id: msg.id,
        sender: msg.user_id,
        senderName: msg.senderName || "Unknown",
        text: msg.content,
        timestamp: new Date(msg.created_at).getTime(),
        type: msg.message_type,
        photoUrl: msg.media_url,
      })) || []
    );
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const listenToMessages = (
  chatId: string,
  callback: (messages: Message[]) => void
) => {
  const subscription = supabase
    .channel(`messages:${chatId}`)
    .on(
      "postgres_changes",
      {
        event: "*",
        schema: "public",
        table: "messages",
        filter: `chat_id=eq.${chatId}`,
      },
      () => {
        getMessages(chatId).then(callback);
      }
    )
    .subscribe();

  return () => {
    subscription.unsubscribe();
  };
};

